240→/// Pending approval request waiting for gateway resolution.
241→struct PendingApproval {
242→    command: String,
243→    session_key: Option<String>,
244→    tx: oneshot::Sender<ApprovalDecision>,
245→}
246→
247→/// Serializable summary of a pending approval request.
248→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
249→pub struct PendingApprovalView {
250→    pub id: String,
251→    pub command: String,
252→    #[serde(skip_serializing_if = "Option::is_none")]
253→    pub session_key: Option<String>,
254→}
