256→/// The approval manager handles approval flow for exec commands.
257→pub struct ApprovalManager {
258→    pub mode: ApprovalMode,
259→    pub security_level: SecurityLevel,
260→    pub allowlist: Vec<String>,
261→    pub timeout: Duration,
262→    pending: Arc<RwLock<std::collections::HashMap<String, PendingApproval>>>,
263→    approved_commands: Arc<RwLock<HashSet<String>>>,
264→}
265→
266→impl Default for ApprovalManager {
267→    fn default() -> Self {
268→        Self {
269→            mode: ApprovalMode::OnMiss,
270→            security_level: SecurityLevel::Allowlist,
271→            allowlist: Vec::new(),
272→            timeout: Duration::from_secs(120),
273→            pending: Arc::new(RwLock::new(std::collections::HashMap::new())),
274→            approved_commands: Arc::new(RwLock::new(HashSet::new())),
275→        }
276→    }
277→}
278→
279→impl ApprovalManager {
280→    /// Decide whether a command needs approval.
281→    /// Returns Ok(()) if the command can proceed, Err if denied.
282→    pub async fn check_command(&self, command: &str) -> Result<ApprovalAction> {
283→        // Safety floor: dangerous patterns are blocked unless explicitly
284→        // allowlisted. In OnMiss/Always mode we escalate to NeedsApproval so a
285→        // human can gate. In Off mode there is no human approver to wait on,
286→        // so the only safe outcome is to deny — otherwise the agent would hang
287→        // on `NeedsApproval` forever in headless deployments (moltis-org/moltis#654).
288→        if let Some(desc) = check_dangerous(command) {
289→            if !matches_allowlist(command, &self.allowlist) {
290→                if self.mode == ApprovalMode::Off {
291→                    warn!(
292→                        command,
293→                        pattern = %desc,
294→                        "dangerous command denied in approval_mode=off",
295→                    );
296→                    return Err(Error::message(format!(
297→                        "exec denied: dangerous command pattern '{desc}' (approval_mode=off): \
298→                         {command}"
299→                    )));
300→                }
301→                warn!(command, pattern = %desc, "dangerous command detected, forcing approval");
302→                return Ok(ApprovalAction::NeedsApproval);
303→            }
304→            debug!(command, pattern = %desc, "dangerous command allowed by explicit allowlist");
305→        }
306→
307→        match self.security_level {
308→            SecurityLevel::Deny => {
309→                return Err(Error::message("exec denied: security level is 'deny'"));
310→            },
311→            SecurityLevel::Full => return Ok(ApprovalAction::Proceed),
312→            SecurityLevel::Allowlist => {},
313→        }
314→
315→        match self.mode {
316→            ApprovalMode::Off => {
317→                // With an empty allowlist, Off mode is unrestricted (preserves
318→                // historical behavior for deployments that never configured a list).
319→                // With a non-empty allowlist, the list is authoritative: the user
320→                // explicitly asked for enforcement, and there is no human to prompt
321→                // in headless deployments — non-matches must be denied, not silently
322→                // proceeded (moltis-org/moltis#654).
323→                if self.allowlist.is_empty() {
324→                    return Ok(ApprovalAction::Proceed);
325→                }
326→                if matches_allowlist(command, &self.allowlist) {
327→                    return Ok(ApprovalAction::Proceed);
328→                }
329→                if is_safe_command(command) {
330→                    // Safe bins bypass the explicit allowlist so operators don't
331→                    // have to enumerate common read-only utilities. Emit a warn
332→                    // so strict-posture operators can detect the gap at runtime
333→                    // (they can `grep safe-bin` their logs to audit, or file a
334→                    // follow-up for an opt-in strict mode that gates safe bins).
335→                    warn!(
336→                        command,
337→                        "exec safe-bin bypassed non-empty allowlist in approval_mode=off",
338→                    );
339→                    return Ok(ApprovalAction::Proceed);
340→                }
341→                Err(Error::message(format!(
342→                    "exec denied: command not in allowlist (approval_mode=off): {command}"
343→                )))
344→            },
345→            ApprovalMode::Always => Ok(ApprovalAction::NeedsApproval),
346→            ApprovalMode::OnMiss => {
347→                // Check safe bins.
348→                if is_safe_command(command) {
349→                    return Ok(ApprovalAction::Proceed);
350→                }
351→                // Check custom allowlist.
352→                if matches_allowlist(command, &self.allowlist) {
353→                    return Ok(ApprovalAction::Proceed);
354→                }
355→                // Check previously approved.
356→                if self.approved_commands.read().await.contains(command) {
357→                    return Ok(ApprovalAction::Proceed);
358→                }
359→                Ok(ApprovalAction::NeedsApproval)
360→            },
361→        }
362→    }
363→
364→    /// Register a pending approval request. Returns an ID and a receiver for the decision.
365→    pub async fn create_request(
366→        &self,
367→        command: &str,
368→        session_key: Option<&str>,
369→    ) -> (String, oneshot::Receiver<ApprovalDecision>) {
370→        let id = uuid::Uuid::new_v4().to_string();
371→        let (tx, rx) = oneshot::channel();
372→        self.pending
373→            .write()
374→            .await
375→            .insert(id.clone(), PendingApproval {
376→                command: command.to_string(),
377→                session_key: session_key.map(str::to_string),
378→                tx,
379→            });
380→        debug!(id = %id, command, session_key, "approval request created");
381→        (id, rx)
382→    }
383→
384→    /// Resolve a pending approval request.
385→    pub async fn resolve(&self, id: &str, decision: ApprovalDecision, command: Option<&str>) {
386→        if let Some(pending) = self.pending.write().await.remove(id) {
387→            if decision == ApprovalDecision::Approved
388→                && let Some(cmd) = command
389→            {
390→                self.approved_commands.write().await.insert(cmd.to_string());
391→            }
392→            let _ = pending.tx.send(decision);
393→            debug!(id, "approval resolved");
394→        } else {
395→            warn!(id, "approval resolve: no pending request");
396→        }
397→    }
398→
399→    /// Return the IDs of all pending approval requests.
400→    pub async fn pending_ids(&self) -> Vec<String> {
401→        let mut ids: Vec<_> = self.pending.read().await.keys().cloned().collect();
402→        ids.sort();
403→        ids
404→    }
405→
406→    /// Return summaries of all pending approval requests.
407→    pub async fn pending_requests(&self) -> Vec<PendingApprovalView> {
408→        let mut requests: Vec<_> = self
409→            .pending
410→            .read()
411→            .await
412→            .iter()
413→            .map(|(id, pending)| PendingApprovalView {
414→                id: id.clone(),
415→                command: pending.command.clone(),
416→                session_key: pending.session_key.clone(),
417→            })
418→            .collect();
419→        requests.sort_by(|left, right| left.id.cmp(&right.id));
420→        requests
421→    }
422→
423→    /// Return summaries of pending approval requests scoped to a session.
424→    pub async fn pending_requests_for_session(
425→        &self,
426→        session_key: &str,
427→    ) -> Vec<PendingApprovalView> {
428→        self.pending_requests()
429→            .await
430→            .into_iter()
431→            .filter(|request| request.session_key.as_deref() == Some(session_key))
432→            .collect()
433→    }
434→
435→    /// Wait for an approval decision with timeout.
436→    pub async fn wait_for_decision(
437→        &self,
438→        rx: oneshot::Receiver<ApprovalDecision>,
439→    ) -> ApprovalDecision {
440→        match tokio::time::timeout(self.timeout, rx).await {
441→            Ok(Ok(decision)) => decision,
442→            Ok(Err(_)) => {
443→                warn!("approval channel closed");
444→                ApprovalDecision::Denied
445→            },
446→            Err(_) => {
447→                warn!("approval timed out");
448→                ApprovalDecision::Timeout
449→            },
450→        }
451→    }
452→}
