            Some("git force push")
        );
        assert_eq!(
            check_dangerous("git push -f origin main"),
            Some("git force push")
        );
        assert_eq!(
            check_dangerous("git push --force-with-lease origin main"),
            Some("git force push")
        );
    }

    #[test]
    fn test_dangerous_drop_table() {
        assert_eq!(
            check_dangerous(r#"psql -c "DROP TABLE users""#),
