    #[tokio::test]
    async fn test_env_injection_with_explicit_allowlist_wildcard() {
        // Wildcard allowlist still overrides dangerous env var patterns.
        let mgr = ApprovalManager {
            allowlist: vec!["*".into()],
            ..Default::default()
